      musicalBrief: {"storyId": "gen-31f50f685a68", "ageGroup": "6-8", "musicalIdentity": {"culturalReference": "celtic", "primaryLoop": "harp_arpeggios", "padCharacter": "forest_hum"}, "tonality": {"mode": "dorian", "rootNote": "A"}, "melodicCharacter": "cycling_arpeggio", "rhythm": {"feel": "gentle_pulse", "baseTempo": 62}, "environment": {"natureSoundPrimary": "forest_night", "natureSoundSecondary": "distant_stream", "ambientEvents": ["cricket", "leaves"]}, "emotionalArc": {"phase1": "curious_wonder", "phase2": "gentle_journey", "phase3": "deep_stillness"}},
